        let new_top = func + 1 + idx as i32;
        let old_top = state.top_idx();
        if new_top.0 > old_top.0 {
            // C: for (; diff > 0; diff--) setnilvalue(s2v(L->top.p++));
            for i in old_top.0..new_top.0 {
